'use client';

import { useEffect, useState } from 'react';
import { ArrowUp } from 'lucide-react';

export function ScrollToTop() {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const main = document.getElementById('main-scroll');
    if (!main) return;
    const onScroll = () => setVisible(main.scrollTop > 300);
    main.addEventListener('scroll', onScroll);
    return () => main.removeEventListener('scroll', onScroll);
  }, []);

  function scrollTop() {
    document.getElementById('main-scroll')?.scrollTo({ top: 0, behavior: 'smooth' });
  }

  if (!visible) return null;

  return (
    <button
      onClick={scrollTop}
      className="fixed bottom-8 right-8 z-50 w-11 h-11 rounded-full bg-surface-overlay border border-surface-border-light text-zinc-300 hover:text-white hover:bg-brand-500 hover:border-brand-500 shadow-lg shadow-black/30 flex items-center justify-center transition-all duration-200 animate-fade-in"
      aria-label="맨 위로"
    >
      <ArrowUp className="w-4 h-4" />
    </button>
  );
}
