'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Zap, TrendingUp, User, Settings, Hexagon, PanelLeftClose, PanelLeftOpen } from 'lucide-react';
import { useState } from 'react';

const navItems = [
  { icon: Zap,        label: '결정 피드', path: '/feed' },
  { icon: TrendingUp, label: '트렌드',    path: '/trends' },
  { icon: User,       label: '프로필',    path: '/profile' },
];

export function Sidebar() {
  const pathname = usePathname();
  const [collapsed, setCollapsed] = useState(false);

  return (
    <aside
      className={`h-screen sticky top-0 bg-surface-base border-r border-surface-border flex-col hidden md:flex transition-all duration-300 ${
        collapsed ? 'w-16' : 'w-64'
      }`}
    >
      {/* 로고 + 토글 버튼 */}
      <div className="h-16 flex items-center justify-between px-4 border-b border-surface-border shrink-0">
        <Link
          href="/"
          className={`flex items-center gap-2 text-white font-bold tracking-wider hover:opacity-80 transition-opacity ${
            collapsed ? 'justify-center w-full' : ''
          }`}
        >
          <Hexagon className="w-6 h-6 text-brand-500 fill-brand-500/20 shrink-0" />
          {!collapsed && <span>KITPICK</span>}
        </Link>

        {!collapsed && (
          <button
            onClick={() => setCollapsed(true)}
            className="p-1.5 rounded-lg text-zinc-500 hover:text-zinc-200 hover:bg-surface-raised transition-colors"
            aria-label="메뉴 닫기"
          >
            <PanelLeftClose className="w-4 h-4" />
          </button>
        )}
      </div>

      {collapsed && (
        <div className="flex justify-center pt-3 px-2">
          <button
            onClick={() => setCollapsed(false)}
            className="p-1.5 rounded-lg text-zinc-500 hover:text-zinc-200 hover:bg-surface-raised transition-colors"
            aria-label="메뉴 열기"
          >
            <PanelLeftOpen className="w-4 h-4" />
          </button>
        </div>
      )}

      <nav className="flex-1 px-3 py-6 space-y-1">
        {!collapsed && (
          <div className="px-3 mb-2 text-xs font-semibold text-zinc-500 uppercase tracking-wider">
            메뉴
          </div>
        )}
        {navItems.map((item) => {
          const isActive = pathname === item.path;
          return (
            <Link
              key={item.path}
              href={item.path}
              title={collapsed ? item.label : undefined}
              className={`flex items-center rounded-lg text-sm font-medium transition-colors ${
                collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'
              } ${
                isActive
                  ? 'bg-brand-500/10 text-brand-500'
                  : 'text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised'
              }`}
            >
              <item.icon className="w-4 h-4 shrink-0" />
              {!collapsed && item.label}
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-surface-border">
        <button
          title={collapsed ? '설정' : undefined}
          className={`flex items-center rounded-lg text-sm font-medium text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised transition-colors w-full ${
            collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'
          }`}
        >
          <Settings className="w-4 h-4 shrink-0" />
          {!collapsed && '설정'}
        </button>
      </div>
    </aside>
  );
}
